import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const Register = ({ setToken }) => {
  const [username, setUsername] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [phone, setPhone] = useState('');
  const navigate = useNavigate();

  const handleRegister = async () => {
  try {
    const res = await axios.post('http://localhost:5000/api/v1/auth/register', {
      username, email, password, phone,
      lat: 18.5204, lng: 73.8567
    });
    const newToken = res.data.token;
    localStorage.setItem('token', newToken);
    setToken(newToken);
    navigate('/locator');
  } catch (error) {
    alert('Registration failed!');
  }
};

  return (
    <div className="register-page">
      <h2>📝 Register for Eco Bright</h2>
      <input type="text" placeholder="Username" onChange={(e) => setUsername(e.target.value)} className="input-field" />
      <input type="email" placeholder="Email" onChange={(e) => setEmail(e.target.value)} className="input-field" />
      <input type="password" placeholder="Password" onChange={(e) => setPassword(e.target.value)} className="input-field" />
      <input type="text" placeholder="Phone" onChange={(e) => setPhone(e.target.value)} className="input-field" />
      <button onClick={handleRegister} className="btn-primary">
        REGISTER
      </button>
      <p>Already have an account? <a href="/login">Login</a></p>
    </div>
  );
};

export default Register;
